#!/usr/bin/env python3
"""Apply full ext4 read/write, journal, and xattr fixes.

This self-contained helper expands the two generated patchers and executes them
in order from the repository root:
  1. apply_ext4_full_rw_fix.py
  2. apply_ext4_journal_xattr_fix.py
"""
from pathlib import Path
import base64, gzip, json, runpy

PAYLOAD = """

""".replace("\n", "")

def main():
    files = json.loads(gzip.decompress(base64.b64decode(PAYLOAD)).decode())
    root = Path.cwd()
    for name, content in files.items():
        path = root / name
        path.write_text(content)
        try:
            path.chmod(0o755)
        except Exception:
            pass
    runpy.run_path(str(root / 'apply_ext4_full_rw_fix.py'), run_name='__main__')
    runpy.run_path(str(root / 'apply_ext4_journal_xattr_fix.py'), run_name='__main__')

if __name__ == '__main__':
    main()
